if score >= 90:
    print('Excellent!')
elif score >= 70:
    print('Good!')
elif score >= 50:
    print('Pass!')
else:
    print('Fail!')

# if, elif, else combination
temperature = 15
if temperature > 30:
    print('Very hot!')
elif temperature > 20:
    print('Warm!')
elif temperature > 10:
    print('Cool!')
else:
    print('Cold!')

# Multiple conditions
age = 25
if age < 13:
    print('Child')
elif age < 18:
    print('Teenager')
elif age < 30:
    print('Young adult')
elif age < 60:
    print('Adult')
else:
    print('Senior')

# Nested conditions with elif
age = 20
has_permission = True

if age >= 18:
    if has_permission:
        print('Access granted!')
    else:
        print('No permission!')
elif age >= 13:
    print('Teenager, no permission check needed.')
else:
    print('Child, access denied!')

# Python code
score = 85
if score >= 90:
    print('Excellent!')
elif score >= 70:
    print('Good!')
else:
    print('Fail!')

// JavaScript code
let score = 85;
if (score >= 90) {
    console.log('Excellent!');
} else if (score >= 70) {
    console.log('Good!');
} else {
    console.log('Fail!');
}

# Error handling
score = '85'
try:
    score = int(score)
    if score >= 90:
        print('Excellent!')
    elif score >= 70:
        print('Good!')
    elif score >= 50:
        print('Pass!')
    else:
        print('Fail!')
except ValueError:
    print('Error: Score must be a number!')

