# Пример elif
score = 75
if score >= 90:
    print('Отлично!')
elif score >= 70:
    print('Хорошо!')
elif score >= 50:
    print('Удовлетворительно!')
else:
    print('Не сдали!')

# Комбинация if, elif, else
temperature = 15
if temperature > 30:
    print('Очень жарко!')
elif temperature > 20:
    print('Тепло!')
elif temperature > 10:
    print('Прохладно!')
else:
    print('Холодно!')

# Множественные условия
age = 25
if age < 13:
    print('Ребенок')
elif age < 18:
    print('Подросток')
elif age < 30:
    print('Молодой взрослый')
elif age < 60:
    print('Взрослый')
else:
    print('Пожилой')

# Вложенные условия с elif
age = 20
has_permission = True

if age >= 18:
    if has_permission:
        print('Доступ разрешен!')
    else:
        print('Нет разрешения!')
elif age >= 13:
    print('Подросток, проверка разрешения не требуется.')
else:
    print('Ребенок, доступ запрещен!')

